import hashlib
import secrets
import time
import urllib.parse
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs, urlencode


class OAuthAuthorizationServer:
    """OAuth 2.0 Authorization Server with secure redirect URI validation."""

    def __init__(self):
        self.registered_clients = {}
        self.authorization_codes = {}
        self.access_tokens = {}

    def register_client(self, client_id, client_secret, redirect_uris):
        """
        Register a client with exact redirect URIs.
        
        Each deployment environment (dev, staging, prod) should register
        its own exact redirect URI. For example:
          - https://app.example.com/callback
          - https://staging.app.example.com/callback
          - https://dev.app.example.com/callback
        """
        validated_uris = []
        for uri in redirect_uris:
            parsed = urlparse(uri)
            if parsed.scheme not in ('https',):
                # Allow http only for localhost development
                if parsed.scheme == 'http' and parsed.hostname in ('localhost', '127.0.0.1'):
                    validated_uris.append(uri)
                else:
                    raise ValueError(
                        f"Redirect URI must use HTTPS (except localhost): {uri}"
                    )
            else:
                validated_uris.append(uri)

        self.registered_clients[client_id] = {
            'client_secret': hashlib.sha256(client_secret.encode()).hexdigest(),
            'redirect_uris': validated_uris,
        }
        return True

    def validate_redirect_uri(self, client_id, redirect_uri):
        """
        Validate redirect URI using exact string matching.
        
        SECURITY: We use exact match comparison, NOT substring/prefix matching.
        
        Using startswith() or substring matching for redirect URIs is a well-known
        OAuth vulnerability (CWE-601: Open Redirect). An attacker could register
        a domain like "https://app.example.com.evil.com/callback" which would pass
        a prefix check against "https://app.example.com" but redirect tokens to
        an attacker-controlled server.
        
        Per RFC 6749 Section 3.1.2.3, the authorization server MUST compare
        redirect URIs using exact string matching.
        """
        if client_id not in self.registered_clients:
            return False

        client = self.registered_clients[client_id]
        registered_uris = client['redirect_uris']

        # SECURE: Exact string match comparison per RFC 6749
        # Each environment must register its own complete redirect URI
        for registered_uri in registered_uris:
            if redirect_uri == registered_uri:
                return True

        return False

    def generate_authorization_code(self, client_id, redirect_uri, scope, state):
        """Generate an authorization code for the client."""
        if not self.validate_redirect_uri(client_id, redirect_uri):
            return None, "Invalid redirect URI"

        code = secrets.token_urlsafe(32)
        self.authorization_codes[code] = {
            'client_id': client_id,
            'redirect_uri': redirect_uri,
            'scope': scope,
            'state': state,
            'created_at': time.time(),
            'used': False,
        }
        return code, None

    def exchange_code_for_token(self, code, client_id, client_secret, redirect_uri):
        """Exchange an authorization code for an access token."""
        if code not in self.authorization_codes:
            return None, "Invalid authorization code"

        code_data = self.authorization_codes[code]

        if code_data['used']:
            # Revoke any tokens issued with this code (replay detection)
            self._revoke_tokens_for_code(code)
            return None, "Authorization code already used"

        if time.time() - code_data['created_at'] > 600:
            del self.authorization_codes[code]
            return None, "Authorization code expired"

        if code_data['client_id'] != client_id:
            return None, "Client ID mismatch"

        stored_secret_hash = self.registered_clients[client_id]['client_secret']
        provided_secret_hash = hashlib.sha256(client_secret.encode()).hexdigest()
        if not secrets.compare_digest(stored_secret_hash, provided_secret_hash):
            return None, "Invalid client secret"

        # SECURE: Exact match on redirect_uri during token exchange as well
        if code_data['redirect_uri'] != redirect_uri:
            return None, "Redirect URI mismatch"

        code_data['used'] = True

        access_token = secrets.token_urlsafe(32)
        refresh_token = secrets.token_urlsafe(32)
        self.access_tokens[access_token] = {
            'client_id': client_id,
            'scope': code_data['scope'],
            'created_at': time.time(),
            'expires_in': 3600,
            'code': code,
        }

        return {
            'access_token': access_token,
            'token_type': 'Bearer',
            'expires_in': 3600,
            'refresh_token': refresh_token,
            'scope': code_data['scope'],
        }, None

    def _revoke_tokens_for_code(self, code):
        """Revoke all tokens associated with a given authorization code."""
        tokens_to_revoke = [
            token for token, data in self.access_tokens.items()
            if data.get('code') == code
        ]
        for token in tokens_to_revoke:
            del self.access_tokens[token]

    def validate_access_token(self, token):
        """Validate an access token."""
        if token not in self.access_tokens:
            return None

        token_data = self.access_tokens[token]
        if time.time() - token_data['created_at'] > token_data['expires_in']:
            del self.access_tokens[token]
            return None

        return token_data


class OAuthRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for the OAuth authorization server."""

    server_instance = OAuthAuthorizationServer()

    def do_GET(self):
        parsed = urlparse(self.path)
        params = parse_qs(parsed.query)

        if parsed.path == '/authorize':
            self.handle_authorize(params)
        else:
            self.send_error(404)

    def do_POST(self):
        parsed = urlparse(self.path)
        content_length = int(self.headers.get('Content-Length', 0))
        body = self.rfile.read(content_length).decode('utf-8')
        params = parse_qs(body)

        if parsed.path == '/token':
            self.handle_token(params)
        elif parsed.path == '/register':
            self.handle_register(params)
        else:
            self.send_error(404)

    def handle_authorize(self, params):
        client_id = params.get('client_id', [None])[0]
        redirect_uri = params.get('redirect_uri', [None])[0]
        scope = params.get('scope', [''])[0]
        state = params.get('state', [None])[0]
        response_type = params.get('response_type', [None])[0]

        if not all([client_id, redirect_uri, response_type]):
            self.send_error(400, "Missing required parameters")
            return

        if response_type != 'code':
            self.send_error(400, "Unsupported response type")
            return

        # Validate redirect URI BEFORE using it for any redirect
        if not self.server_instance.validate_redirect_uri(client_id, redirect_uri):
            # Do NOT redirect to the invalid URI - return error directly
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            import json
            self.wfile.write(json.dumps({
                'error': 'invalid_redirect_uri',
                'error_description': 'The redirect URI does not match any registered URI for this client. '
                                     'Each environment must register its exact redirect URI.'
            }).encode())
            return

        code, error = self.server_instance.generate_authorization_code(
            client_id, redirect_uri, scope, state
        )

        if error:
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            import json
            self.wfile.write(json.dumps({'error': error}).encode())
            return

        # Build redirect with authorization code
        redirect_params = {'code': code}
        if state:
            redirect_params['state'] = state

        separator = '&' if '?' in redirect_uri else '?'
        final_redirect = redirect_uri + separator + urlencode(redirect_params)

        self.send_response(302)
        self.send_header('Location', final_redirect)
        self.send_header('Cache-Control', 'no-store')
        self.send_header('Pragma', 'no-cache')
        self.end_headers()

    def handle_token(self, params):
        import json

        grant_type = params.get('grant_type', [None])[0]
        code = params.get('code', [None])[0]
        client_id = params.get('client_id', [None])[0]
        client_secret = params.get('client_secret', [None])[0]
        redirect_uri = params.get('redirect_uri', [None])[0]

        if grant_type != 'authorization_code':
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({
                'error': 'unsupported_grant_type'
            }).encode())
            return

        if not all([code, client_id, client_secret, redirect_uri]):
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({
                'error': 'invalid_request',
                'error_description': 'Missing required parameters'
            }).encode())
            return

        token_response, error = self.server_instance.exchange_code_for_token(
            code, client_id, client_secret, redirect_uri
        )

        if error:
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.send_header('Cache-Control', 'no-store')
            self.end_headers()
            self.wfile.write(json.dumps({'error': error}).encode())
            return

        self.send_response(200)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Cache-Control', 'no-store')
        self.send_header('Pragma', 'no-cache')
        self.end_headers()
        self.wfile.write(json.dumps(token_response).encode())

    def handle_register(self, params):
        import json

        client_id = params.get('client_id', [None])[0]
        client_secret = params.get('client_secret', [None])[0]
        redirect_uris = params.get('redirect_uris', [])

        if not all([client_id, client_secret, redirect_uris]):
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({
                'error': 'Missing required parameters'
            }).encode())
            return

        try:
            self.server_instance.register_client(
                client_id, client_secret, redirect_uris
            )
            self.send_response(201)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({
                'status': 'registered',
                'client_id': client_id,
                'redirect_uris': redirect_uris,
                'note': 'Each redirect URI is matched exactly. Register separate URIs for each environment.'
            }).encode())
        except ValueError as e:
            self.send_response(400)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({'error': str(e)}).encode())


