        ('https://staging.app.example.com/callback', True, 'Exact match (staging)'),
        ('http://localhost:8080/callback', True, 'Exact match (local dev)'),
        # Attack vectors that would pass with startswith() but fail with exact match
        ('https://app.example.com/callback?extra=param', False, 'Extra query params'),
